mapper.select:
SELECT r.`id`, r.`emp_id` AS empId, r.`resign_type` AS resignType, r.`resign_reason` AS resignReason, DATE_FORMAT(r.`expect_resign_date`, '%Y-%m-%d') AS expectResignDate, r.`approver_id` AS approverId, DATE_FORMAT(r.`approve_time`, '%Y-%m-%d %H:%i:%s') AS approveTime, r.`approve_remark` AS approveRemark, r.`status` AS status, DATE_FORMAT(r.`actual_resign_date`, '%Y-%m-%d') AS actualResignDate, DATE_FORMAT(r.`create_time`, '%Y-%m-%d %H:%i:%s') AS createTime, DATE_FORMAT(r.`update_time`, '%Y-%m-%d %H:%i:%s') AS updateTime, e1.`name` AS applyName, e2.`name` AS approverName FROM employee_resignation r LEFT JOIN employee e1 ON r.emp_id = e1.id LEFT JOIN employee e2 ON r.approver_id = e2.id where 1=1
and r.emp_id = #{empId,jdbcType=INTEGER} or r.approver_id = #{empId,jdbcType=INTEGER}
limit #{page},#{size}
